#include<bits/stdc++.h>
using namespace std;
int x[100010],h[100010];
int n,d;
struct st
{
    int lg[50010];
    int f[50010][22],f1[50010][22];
    void init()
    {
        lg[1]=0;
        for(int i=2;i<=n;i++)
        {
            lg[i]=lg[i/2]+1;
        }
        for(int i=1;i<=n;i++)
        {
            f[i][0]=f1[i][0]=h[i];
        }
        for(int j=1;j<=lg[n];j++)
        {
            for(int i=1;i<=n-(1<<j)+1;i++)
            {
                f[i][j]=max(f[i][j-1],f[i+(1<<(j-1))][j-1]);
                f1[i][j]=min(f1[i][j-1],f1[i+(1<<(j-1))][j-1]);
            }
        }
    }
    int getmax(int l,int r)
    {
        int temp=lg[r-l+1];
        return max(f[l][temp],f[r-(1<<temp)+1][temp]);
    }
    int getmin(int l,int r)
    {
        int temp=lg[r-l+1];
        return min(f1[l][temp],f1[r-(1<<temp)+1][temp]);
    }
}s;
struct node
{
    int x,h;
    bool operator<(const node&b)const
    {
        return x<b.x;
    }
}a[100010];
int main()
{
    scanf("%d%d",&n,&d);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i].x,&a[i].h);
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        x[i]=a[i].x;
        h[i]=a[i].h;
    }
    s.init();
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        int l=lower_bound(x+1,x+1+n,x[i]-d)-x;
        int r=upper_bound(x+1,x+1+n,x[i]+d)-x-1;
        if(s.getmax(l,i)>=h[i]*2&&s.getmax(i,r)>=h[i]*2)
        {
            ans++;
        }
    }
    printf("%d",ans);
    return 0;
}
